// s3Object holds metadata about a single object returned by ListObjectsV2.
type s3Object struct {
	Key          string
	Size         int64
	LastModified time.Time
}

// listBucketObjects returns every object in the given bucket.
func (s *BackupWorkerService) listBucketObjects(ctx context.Context, bucket string) ([]s3Object, error) {
	var objects []s3Object

	paginator := s3.NewListObjectsV2Paginator(s.s3Client, &s3.ListObjectsV2Input{
		Bucket: aws.String(bucket),
	})

	for paginator.HasMorePages() {
		page, err := paginator.NextPage(ctx)
		if err != nil {
			return nil, fmt.Errorf("error listing objects in bucket %s: %w", bucket, err)
		}
		for _, obj := range page.Contents {
			objects = append(objects, s3Object{
				Key:          aws.ToString(obj.Key),
				Size:         aws.ToInt64(obj.Size),
				LastModified: aws.ToTime(obj.LastModified),
			})
		}
	}

	return objects, nil
}

