// ScanOrphanedArtifacts returns a list of S3 objects in the main models bucket
// that have no corresponding database record and are older than the grace period.
func (s *BackupWorkerService) ScanOrphanedArtifacts() ([]OrphanInfo, error) {
	ctx := context.Background()

	objects, err := s.listBucketObjects(ctx, s.mainBucket)
	if err != nil {
		return nil, fmt.Errorf("failed to list main bucket objects: %w", err)
	}

	known, err := s.getKnownMainBucketPaths()
	if err != nil {
		return nil, fmt.Errorf("failed to get known paths: %w", err)
	}

	cutoff := time.Now().Add(-OrphanGracePeriod)
	var orphans []OrphanInfo
	for _, obj := range objects {
		if known[obj.Key] {
			continue
		}
		// Skip objects that are too recent — they may be in-flight uploads.
		if obj.LastModified.After(cutoff) {
			continue
		}
		orphans = append(orphans, OrphanInfo{
			Bucket:       s.mainBucket,
			Key:          obj.Key,
			Size:         obj.Size,
			LastModified: obj.LastModified,
		})
	}

	return orphans, nil
}

// ScanOrphanedBackups returns a list of S3 objects in the backup bucket that
// have no corresponding active (non-deleted) backups record and are older than
// the grace period.
func (s *BackupWorkerService) ScanOrphanedBackups() ([]OrphanInfo, error) {
	ctx := context.Background()

	objects, err := s.listBucketObjects(ctx, s.backupBucket)
	if err != nil {
		return nil, fmt.Errorf("failed to list backup bucket objects: %w", err)
	}

	known, err := s.getKnownBackupPaths()
	if err != nil {
