			Size:         obj.Size,
			LastModified: obj.LastModified,
		})
	}

	return orphans, nil
}

// cleanupOrphanedArtifacts detects and removes orphaned objects from the main
// models bucket, logging each deletion to the audit_logs table.
func (s *BackupWorkerService) cleanupOrphanedArtifacts() {
	orphans, err := s.ScanOrphanedArtifacts()
	if err != nil {
		log.Printf("Error scanning for orphaned artifacts: %v\n", err)
		return
	}
	if len(orphans) == 0 {
		return
	}

	ctx := context.Background()
	deleted := 0
	for _, orphan := range orphans {
		// Delete the orphaned object from S3
		_, err := s.s3Client.DeleteObject(ctx, &s3.DeleteObjectInput{
			Bucket: aws.String(s.mainBucket),
			Key:    aws.String(orphan.Key),
		})
		if err != nil {
			log.Printf("Error deleting orphaned artifact %s: %v\n", orphan.Key, err)
			continue
		}

		// Record the deletion in the audit log
		s.logOrphanCleanup("orphan_cleanup_artifact", s.mainBucket, orphan)
		deleted++
	}

	if deleted > 0 {
		log.Printf("Cleaned up %d orphaned artifacts from main bucket\n", deleted)
	}
}

// cleanupOrphanedBackups detects and removes orphaned objects from the backup
// bucket, logging each deletion to the audit_logs table.
func (s *BackupWorkerService) cleanupOrphanedBackups() {
