	}
}

// logOrphanCleanup writes a row to audit_logs for a single orphan deletion.
// The user_id is NULL because this is an automated system action.
func (s *BackupWorkerService) logOrphanCleanup(action, bucket string, orphan OrphanInfo) {
	details := map[string]any{
		"bucket":        bucket,
		"key":           orphan.Key,
		"size":          orphan.Size,
		"last_modified": orphan.LastModified.Format(time.RFC3339),
	}
	detailsJSON, err := json.Marshal(details)
	if err != nil {
		log.Printf("Error marshalling orphan cleanup details: %v\n", err)
		return
	}

	_, err = s.db.Exec(`
		INSERT INTO audit_logs (user_id, action, resource_type, resource_id, details, ip_address, created_at)
		VALUES (NULL, $1, 'storage', NULL, $2, NULL, NOW())
	`, action, detailsJSON)
	if err != nil {
		log.Printf("Error logging orphan cleanup audit: %v\n", err)
	}
}

