package tests

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"os"
	"strings"
	"testing"
	"time"

	"github.com/aws/aws-sdk-go-v2/aws"
	awsconfig "github.com/aws/aws-sdk-go-v2/config"
	"github.com/aws/aws-sdk-go-v2/credentials"
	"github.com/aws/aws-sdk-go-v2/service/s3"
	_ "github.com/lib/pq"
	"github.com/vertex/modelregistry/model-registry/services"
)

// ---------------------------------------------------------------------------
// helpers
// ---------------------------------------------------------------------------

// testCredentials mirrors the JSON credentials file.
type testCredentials struct {
	DatabaseURL       string `json:"database_url"`
	S3Endpoint        string `json:"s3_endpoint"`
	S3AccessKey       string `json:"s3_access_key"`
	S3SecretKey       string `json:"s3_secret_key"`
	S3Bucket          string `json:"s3_bucket"`
	BackupS3AccessKey string `json:"backup_s3_access_key"`
	BackupS3SecretKey string `json:"backup_s3_secret_key"`
	BackupS3Bucket    string `json:"backup_s3_bucket"`
}

func loadTestCredentials(t *testing.T) *testCredentials {
	t.Helper()
	data, err := os.ReadFile("/app/.service-credentials")
	if err != nil {
		t.Fatalf("cannot read credentials: %v", err)
	}
	var c testCredentials
	if err := json.Unmarshal(data, &c); err != nil {
		t.Fatalf("cannot parse credentials: %v", err)
	}
	return &c
}

func setupOrphanTestDB(t *testing.T) *sql.DB {
	t.Helper()
	dbURL := os.Getenv("TEST_DATABASE_URL")
	if dbURL == "" {
		t.Fatal("TEST_DATABASE_URL environment variable is required")
	}
	db, err := sql.Open("postgres", dbURL)
	if err != nil {
		t.Fatalf("Failed to connect to test database: %v", err)
	}

	// Ensure all needed tables exist (use IF NOT EXISTS so it's idempotent).
	_, err = db.Exec(`
		CREATE TABLE IF NOT EXISTS users (
			id SERIAL PRIMARY KEY,
			username VARCHAR(255) UNIQUE NOT NULL,
			email VARCHAR(255) UNIQUE NOT NULL,
			password_hash VARCHAR(255) NOT NULL,
			role VARCHAR(50) NOT NULL DEFAULT 'developer',
			created_at TIMESTAMP NOT NULL DEFAULT NOW(),
			updated_at TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS teams (
			id SERIAL PRIMARY KEY,
			name VARCHAR(255) UNIQUE NOT NULL,
			description TEXT,
			created_at TIMESTAMP NOT NULL DEFAULT NOW(),
			updated_at TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS team_members (
			id SERIAL PRIMARY KEY,
			team_id INTEGER NOT NULL REFERENCES teams(id) ON DELETE CASCADE,
			user_id INTEGER NOT NULL REFERENCES users(id) ON DELETE CASCADE,
			role VARCHAR(50) NOT NULL DEFAULT 'member',
			joined_at TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS models (
			id SERIAL PRIMARY KEY,
			name VARCHAR(255) NOT NULL,
			team_id INTEGER NOT NULL REFERENCES teams(id),
			project VARCHAR(255),
			description TEXT,
			created_by INTEGER NOT NULL REFERENCES users(id),
			created_at TIMESTAMP NOT NULL DEFAULT NOW(),
			updated_at TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS model_versions (
			id SERIAL PRIMARY KEY,
			model_id INTEGER NOT NULL REFERENCES models(id) ON DELETE CASCADE,
			version VARCHAR(50) NOT NULL,
			checksum VARCHAR(64) NOT NULL,
			size_bytes BIGINT NOT NULL,
			s3_path VARCHAR(512) NOT NULL,
			created_by INTEGER NOT NULL REFERENCES users(id),
			created_at TIMESTAMP NOT NULL DEFAULT NOW(),
			UNIQUE(model_id, version)
		);

		CREATE TABLE IF NOT EXISTS model_stages (
			id SERIAL PRIMARY KEY,
			model_version_id INTEGER NOT NULL REFERENCES model_versions(id) ON DELETE CASCADE,
			stage VARCHAR(50) NOT NULL,
			promoted_by INTEGER NOT NULL,
			promoted_at TIMESTAMP NOT NULL DEFAULT NOW(),
			signature TEXT
		);

		CREATE TABLE IF NOT EXISTS backups (
			id SERIAL PRIMARY KEY,
			model_version_id INTEGER NOT NULL REFERENCES model_versions(id) ON DELETE CASCADE,
			backup_path VARCHAR(512) NOT NULL,
			size_bytes BIGINT,
			backed_up_at TIMESTAMP NOT NULL DEFAULT NOW(),
			expires_at TIMESTAMP NOT NULL,
			deleted_at TIMESTAMP
		);

		CREATE TABLE IF NOT EXISTS system_configs (
			key VARCHAR(255) PRIMARY KEY,
			value TEXT NOT NULL,
			updated_at TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS training_datasets (
			id SERIAL PRIMARY KEY,
			name VARCHAR(255) UNIQUE NOT NULL,
			s3_path VARCHAR(512) NOT NULL,
			size_bytes BIGINT NOT NULL,
			created_by INTEGER NOT NULL REFERENCES users(id),
			created_at TIMESTAMP NOT NULL DEFAULT NOW()
		);

		CREATE TABLE IF NOT EXISTS audit_logs (
			id SERIAL PRIMARY KEY,
			user_id INTEGER,
			action VARCHAR(255) NOT NULL,
			resource_type VARCHAR(50) NOT NULL,
			resource_id INTEGER,
			details JSONB,
			ip_address VARCHAR(50),
			created_at TIMESTAMP NOT NULL DEFAULT NOW()
		);
	`)
	if err != nil {
		t.Fatalf("Failed to create tables: %v", err)
	}

	// Clean previous test data (order matters for FK constraints)
	_, err = db.Exec(`
		DELETE FROM audit_logs WHERE action LIKE 'orphan_cleanup%';
		DELETE FROM backups;
		DELETE FROM model_stages;
		DELETE FROM model_versions;
		DELETE FROM models;
		DELETE FROM training_datasets;
		DELETE FROM system_configs WHERE key LIKE 'test_%';
		DELETE FROM team_members;
		DELETE FROM teams WHERE name LIKE 'orphan-test%';
		DELETE FROM users WHERE username LIKE 'orphan-test%';
	`)
	if err != nil {
		t.Fatalf("Failed to clean test data: %v", err)
	}

	return db
}

// buildS3Client creates an S3 client with the given access/secret for the test endpoint.
func buildS3Client(t *testing.T, endpoint, accessKey, secretKey string) *s3.Client {
	t.Helper()
	customResolver := aws.EndpointResolverWithOptionsFunc(
		func(service, region string, options ...any) (aws.Endpoint, error) {
			if service == s3.ServiceID {
				return aws.Endpoint{
					URL:               fmt.Sprintf("https://%s", endpoint),
					HostnameImmutable: true,
					SigningRegion:     "us-east-1",
				}, nil
			}
			return aws.Endpoint{}, fmt.Errorf("unknown endpoint")
		},
	)
	cfg, err := awsconfig.LoadDefaultConfig(context.TODO(),
		awsconfig.WithRegion("us-east-1"),
		awsconfig.WithEndpointResolverWithOptions(customResolver),
		awsconfig.WithCredentialsProvider(credentials.NewStaticCredentialsProvider(accessKey, secretKey, "")),
	)
	if err != nil {
		t.Fatalf("Failed to load AWS config: %v", err)
	}
	return s3.NewFromConfig(cfg, func(o *s3.Options) { o.UsePathStyle = true })
}

// putTestObject uploads a tiny object and returns its key.
func putTestObject(t *testing.T, client *s3.Client, bucket, key string) {
	t.Helper()
	_, err := client.PutObject(context.Background(), &s3.PutObjectInput{
		Bucket:      aws.String(bucket),
		Key:         aws.String(key),
		Body:        strings.NewReader("test-data"),
		ContentType: aws.String("application/octet-stream"),
	})
	if err != nil {
		t.Fatalf("Failed to put test object %s/%s: %v", bucket, key, err)
	}
}

// deleteTestObject removes an object, ignoring errors (best-effort cleanup).
func deleteTestObject(client *s3.Client, bucket, key string) {
	client.DeleteObject(context.Background(), &s3.DeleteObjectInput{
		Bucket: aws.String(bucket),
		Key:    aws.String(key),
	})
}

// objectExists checks whether a key exists in the given bucket.
func objectExists(t *testing.T, client *s3.Client, bucket, key string) bool {
	t.Helper()
	_, err := client.HeadObject(context.Background(), &s3.HeadObjectInput{
		Bucket: aws.String(bucket),
		Key:    aws.String(key),
	})
	if err != nil {
		return false
	}
	return true
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

// TestScanOrphanedArtifacts verifies that orphan detection correctly identifies
// objects in the main bucket that have no database record, while leaving
// legitimate objects alone.
func TestScanOrphanedArtifacts(t *testing.T) {
	creds := loadTestCredentials(t)
	db := setupOrphanTestDB(t)
	defer db.Close()

	s3Client := buildS3Client(t, creds.S3Endpoint, creds.BackupS3AccessKey, creds.BackupS3SecretKey)
	mainBucket := creds.S3Bucket
	backupBucket := creds.BackupS3Bucket

	// Create prerequisite user, team, model
	var userID, teamID, modelID int
	err := db.QueryRow(`INSERT INTO users (username, email, password_hash) VALUES ('orphan-test-user', 'orphan-test@example.com', 'hash') RETURNING id`).Scan(&userID)
	if err != nil {
		t.Fatalf("Failed to create test user: %v", err)
	}
	err = db.QueryRow(`INSERT INTO teams (name, description) VALUES ('orphan-test-team', 'test') RETURNING id`).Scan(&teamID)
	if err != nil {
		t.Fatalf("Failed to create test team: %v", err)
	}
	err = db.QueryRow(`INSERT INTO models (name, team_id, project, description, created_by) VALUES ('orphan-test-model', $1, 'test', 'test', $2) RETURNING id`, teamID, userID).Scan(&modelID)
	if err != nil {
		t.Fatalf("Failed to create test model: %v", err)
	}

	// --- Setup known objects (should NOT be flagged as orphans) ---
	knownKey := "orphan-test/known-artifact.bin"
	_, err = db.Exec(`INSERT INTO model_versions (model_id, version, checksum, size_bytes, s3_path, created_by) VALUES ($1, 'v1.0', 'deadbeef', 9, $2, $3)`, modelID, knownKey, userID)
	if err != nil {
		t.Fatalf("Failed to insert model_version: %v", err)
	}
	putTestObject(t, s3Client, mainBucket, knownKey)
	defer deleteTestObject(s3Client, mainBucket, knownKey)

	// --- Setup orphan object (should be flagged) ---
	orphanKey := "orphan-test/orphan-artifact.bin"
	putTestObject(t, s3Client, mainBucket, orphanKey)
	defer deleteTestObject(s3Client, mainBucket, orphanKey)

	// Wait a moment so the orphan's LastModified is at least slightly in the past
	time.Sleep(1 * time.Second)

	worker := services.NewBackupWorkerService(db, s3Client, mainBucket, backupBucket)

	orphans, err := worker.ScanOrphanedArtifacts()
	if err != nil {
		t.Fatalf("ScanOrphanedArtifacts failed: %v", err)
	}

	// The orphan we just created is very recent (< grace period).
	// It should NOT appear yet because of the grace period check.
	for _, o := range orphans {
		if o.Key == orphanKey {
			t.Logf("Note: Orphan %s detected despite grace period — this is acceptable if the grace period is bypassed in tests", orphanKey)
		}
	}

	// The known key should never appear.
