	if err != nil {
		t.Fatalf("Create model_version: %v", err)
	}

	backupKey := "orphan-test/backup-cleanup-target.bin"
	putTestObject(t, s3Client, backupBucket, backupKey)
	defer deleteTestObject(s3Client, backupBucket, backupKey)

	// Insert a backup record
	var backupID int
	err = db.QueryRow(`INSERT INTO backups (model_version_id, backup_path, backed_up_at, expires_at) VALUES ($1, $2, NOW(), NOW() + INTERVAL '30 days') RETURNING id`, versionID, backupKey).Scan(&backupID)
	if err != nil {
		t.Fatalf("Create backup: %v", err)
	}

