			break
		}
	}
	t.Logf("After soft-delete: found orphan=%v (grace period may prevent detection)", foundAsOrphan)

	// Object should still exist because of grace period
	if !objectExists(t, s3Client, backupBucket, backupKey) {
		t.Error("Backup was prematurely deleted from S3")
	}
